import{_ as a,o as e,c as i,a2 as n}from"./chunks/framework.C24VBsJ9.js";const b=JSON.parse('{"title":"镜像布局设计 - 这块“假想的盘”里面有什么","description":"","frontmatter":{},"headers":[],"relativePath":"tutorial/flash/05_image_layout_design.md","filePath":"tutorial/flash/05_image_layout_design.md","lastUpdated":1780980021000}'),t={name:"tutorial/flash/05_image_layout_design.md"};function p(l,s,o,d,r,c){return e(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="镜像布局设计-这块-假想的盘-里面有什么" tabindex="-1">镜像布局设计 - 这块“假想的盘”里面有什么 <a class="header-anchor" href="#镜像布局设计-这块-假想的盘-里面有什么" aria-label="Permalink to &quot;镜像布局设计 - 这块“假想的盘”里面有什么&quot;">​</a></h1><h2 id="前言-别把-img-当成一个普通文件系统" tabindex="-1">前言：别把 <code>.img</code> 当成一个普通文件系统 <a class="header-anchor" href="#前言-别把-img-当成一个普通文件系统" aria-label="Permalink to &quot;前言：别把 \`.img\` 当成一个普通文件系统&quot;">​</a></h2><p>第一次看到 <code>imx6ull-aes-emmc.img</code> 的时候，很容易下意识把它理解成“一个 rootfs 镜像”。但它其实不是。</p><p>它更像是一整块 SD 卡或 eMMC 的拷贝。你从第 0 字节开始读，会先遇到分区表；继续往后，会遇到 raw U-Boot；再往后才是 boot 分区和 rootfs 分区。</p><p>这点很重要。因为一旦你把 <code>.img</code> 当成单个 ext4 文件系统来理解，后面很多事情都会觉得奇怪：</p><ul><li>为什么 U-Boot 不在分区里？</li><li>为什么 boot 分区从 16 MiB 开始？</li><li>为什么脚本要用 <code>dd</code> 写三次？</li><li>为什么 <code>sfdisk -d</code> 能看到分区表？</li></ul><p>这一章我们就把这块“假想的盘”拆开来看。</p><h2 id="先看整体长相" tabindex="-1">先看整体长相 <a class="header-anchor" href="#先看整体长相" aria-label="Permalink to &quot;先看整体长相&quot;">​</a></h2><p>当前脚本生成的镜像布局大概是这样：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>offset 0</span></span>
<span class="line"><span>├── MBR 分区表</span></span>
<span class="line"><span>├── 1 KiB: u-boot-dtb.imx</span></span>
<span class="line"><span>├── 16 MiB: boot 分区开始</span></span>
<span class="line"><span>│   ├── zImage</span></span>
<span class="line"><span>│   ├── imx6ull-aes.dtb</span></span>
<span class="line"><span>│   └── boot.cmd</span></span>
<span class="line"><span>└── boot 分区之后: rootfs 分区开始</span></span>
<span class="line"><span>    └── 完整 rootfs</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>把它翻译成默认参数，就是：</p><table tabindex="0"><thead><tr><th>项目</th><th>默认值</th><th>作用</th></tr></thead><tbody><tr><td>U-Boot 偏移</td><td><code>1 KiB</code></td><td>给 i.MX6ULL ROM 启动读取</td></tr><tr><td>boot 分区起点</td><td><code>16 MiB</code></td><td>避开启动区，顺便做清晰对齐</td></tr><tr><td>boot 分区大小</td><td><code>64 MiB</code></td><td>放内核、设备树和启动命令</td></tr><tr><td>rootfs 分区大小</td><td>自动计算</td><td>放完整根文件系统并预留余量</td></tr><tr><td>分区文件系统</td><td>ext4</td><td>boot 和 rootfs 都使用 ext4</td></tr></tbody></table><p>你可以把前 16 MiB 理解成启动前置区域。U-Boot 住在这里，分区从它后面开始。</p><h2 id="为什么-u-boot-要写在-1-kib" tabindex="-1">为什么 U-Boot 要写在 1 KiB <a class="header-anchor" href="#为什么-u-boot-要写在-1-kib" aria-label="Permalink to &quot;为什么 U-Boot 要写在 1 KiB&quot;">​</a></h2><p>U-Boot 在这里不是一个普通文件。它不会被 Linux 挂载，也不属于 boot 分区。</p><p>i.MX6ULL 上电后，ROM Code 会按照启动介质去找符合格式的启动镜像。项目里生成的 <code>u-boot-dtb.imx</code> 已经是 i.MX 平台需要的格式，脚本要做的就是把它放到正确的位置。</p><p>脚本里的动作很直接：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> if=&quot;\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">UBOOT_IMAGE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> of=&quot;\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bs=1K</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> seek=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> conv=notrunc</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这句的意思是：从镜像文件开头跳过 1 KiB，然后把 <code>u-boot-dtb.imx</code> 写进去。</p><p>这里最容易误会的是 <code>conv=notrunc</code>。如果不加它，<code>dd</code> 有可能把目标文件截断。我们前面已经创建了一整个磁盘镜像，后面还要继续写分区文件系统，所以绝对不能让一次 <code>dd</code> 把整盘镜像截掉。</p><h2 id="为什么-boot-分区从-16-mib-开始" tabindex="-1">为什么 boot 分区从 16 MiB 开始 <a class="header-anchor" href="#为什么-boot-分区从-16-mib-开始" aria-label="Permalink to &quot;为什么 boot 分区从 16 MiB 开始&quot;">​</a></h2><p>按理说，U-Boot 只有一两 MiB 左右，那为什么 boot 分区不紧贴着它开始？</p><p>这里是工程上的保守设计。我们给前面留出 16 MiB，有几个好处。</p><p>首先，它能避开 raw U-Boot 区域。以后如果 U-Boot 变大，或者环境区、扩展数据有变化，不至于马上撞到第一个分区。</p><p>其次，16 MiB 是一个很清楚的边界。换算成 512 字节扇区，就是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>16 * 1024 * 1024 / 512 = 32768</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>所以你用 <code>sfdisk -d</code> 看镜像时，会看到第一个分区从 <code>32768</code> 扇区开始：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>...img1 : start=32768, size=131072, type=83, bootable</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个数字一眼就能对上 16 MiB，不需要在脑子里猜“这是哪里来的”。</p><h2 id="为什么-boot-分区也做成-ext4" tabindex="-1">为什么 boot 分区也做成 ext4 <a class="header-anchor" href="#为什么-boot-分区也做成-ext4" aria-label="Permalink to &quot;为什么 boot 分区也做成 ext4&quot;">​</a></h2><p>很多教程会把 boot 分区做成 FAT32。这没错，FAT 对很多 U-Boot 配置都很友好，主机上也容易挂载。</p><p>但在 IMX-Forge 这个脚本里，我们选择了 ext4。不是因为 FAT 不好，而是因为 ext4 更适合当前构建方式。</p><p>当前 U-Boot 已经支持：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ext4load</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>rootfs 本身也是 ext4。更关键的是，<code>mke2fs</code> 有一个很好用的 <code>-d</code> 参数，可以直接把一个目录打进 ext4 文件系统镜像里：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mke2fs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -q</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ext4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">boot_dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;BOOT&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -F</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">boot_fs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这就绕开了一个很讨厌的问题：我们不需要 <code>sudo mount</code> 一个 loop 设备，也不需要在构建脚本里维护挂载和卸载状态。</p><p>构建镜像时，越少碰主机挂载状态越好。否则脚本跑失败后留下一个没卸载的 loop 设备，后面排查起来会很烦。</p><h2 id="boot-分区里为什么放两份内核和-dtb" tabindex="-1">boot 分区里为什么放两份内核和 DTB <a class="header-anchor" href="#boot-分区里为什么放两份内核和-dtb" aria-label="Permalink to &quot;boot 分区里为什么放两份内核和 DTB&quot;">​</a></h2><p>脚本会先构造一个临时目录：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>boot-tree/</span></span>
<span class="line"><span>├── zImage</span></span>
<span class="line"><span>├── imx6ull-aes.dtb</span></span>
<span class="line"><span>├── boot.cmd</span></span>
<span class="line"><span>└── boot/</span></span>
<span class="line"><span>    ├── zImage</span></span>
<span class="line"><span>    └── imx6ull-aes.dtb</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>严格来说，当前自动生成的启动命令用的是根目录下的文件：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ext4load mmc 1:1 \${loadaddr} /zImage</span></span>
<span class="line"><span>ext4load mmc 1:1 \${fdt_addr_r} /imx6ull-aes.dtb</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>那为什么还要在 <code>/boot/</code> 下面再放一份？</p><p>这是为了兼容人的习惯。很多 Linux 系统会把内核文件放在 <code>/boot/</code> 下，很多人手动调试时也会自然去 <code>ext4ls mmc 1:1 /boot</code> 看东西。多放一份成本不高，但能减少“文件到底在哪里”的疑惑。</p><p><code>boot.cmd</code> 则更像是一份启动命令备忘录。它不是现在这套流程里必须自动执行的脚本，但你可以打开它看脚本为这个镜像生成了什么启动参数。</p><h2 id="rootfs-分区怎么决定大小" tabindex="-1">rootfs 分区怎么决定大小 <a class="header-anchor" href="#rootfs-分区怎么决定大小" aria-label="Permalink to &quot;rootfs 分区怎么决定大小&quot;">​</a></h2><p>rootfs 的大小不能拍脑袋。太小，文件系统装不下；太大，每次生成和复制镜像都浪费时间。</p><p>脚本采用一个比较朴素的策略：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rootfs 分区 = rootfs 实际占用 + 25% + 64 MiB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>同时保证最低不小于 128 MiB。</p><p>这个策略适合默认情况：镜像不会大得离谱，又给 rootfs 留出一点上板后写文件的空间。</p><p>如果你明确希望镜像固定大小，比如固定成 1 GiB，可以用：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/image_builder/build_imx6ull_image.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --image-size-mb=1024</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这时脚本会先固定总镜像大小，再把扣掉前置空间和 boot 分区后的剩余空间分给 rootfs。也就是说，多出来的空间不是空洞，而是 rootfs 分区里的可用空间。</p><h2 id="sd-和-emmc-的布局一样吗" tabindex="-1">SD 和 eMMC 的布局一样吗 <a class="header-anchor" href="#sd-和-emmc-的布局一样吗" aria-label="Permalink to &quot;SD 和 eMMC 的布局一样吗&quot;">​</a></h2><p>分区布局基本一样，但启动命令不一样。</p><p>SD 镜像里，U-Boot 从 <code>mmc 0:1</code> 读取内核，Linux 挂载 <code>/dev/mmcblk0p2</code>：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ext4load mmc 0:1 \${loadaddr} /zImage</span></span>
<span class="line"><span>root=/dev/mmcblk0p2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>eMMC 镜像里，U-Boot 从 <code>mmc 1:1</code> 读取内核，Linux 挂载 <code>/dev/mmcblk1p2</code>：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ext4load mmc 1:1 \${loadaddr} /zImage</span></span>
<span class="line"><span>root=/dev/mmcblk1p2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>所以脚本默认用文件名提醒你：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imx6ull-aes-sd.img</span></span>
<span class="line"><span>imx6ull-aes-emmc.img</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这不是为了好看，而是为了避免你后面把 SD/eMMC 参数混了。</p><h2 id="怎么验证布局没跑偏" tabindex="-1">怎么验证布局没跑偏 <a class="header-anchor" href="#怎么验证布局没跑偏" aria-label="Permalink to &quot;怎么验证布局没跑偏&quot;">​</a></h2><p>生成镜像后，不用挂载，先看分区表就行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sfdisk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/release-latest/images/imx6ull-aes-emmc.img</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>你应该看到类似这样的内容：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>label: dos</span></span>
<span class="line"><span>unit: sectors</span></span>
<span class="line"><span></span></span>
<span class="line"><span>...img1 : start=32768, size=131072, type=83, bootable</span></span>
<span class="line"><span>...img2 : start=163840, size=..., type=83</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这里几个数字能对上：</p><ul><li><code>32768</code> 扇区是 16 MiB</li><li><code>131072</code> 扇区是 64 MiB</li><li><code>163840</code> 扇区是 boot 分区结束后的 rootfs 起点</li></ul><p>如果这些数字明显不对，就先别急着烧录。镜像布局都没确认，后面的问题只会更绕。</p><h2 id="接下来我们看脚本怎么做" tabindex="-1">接下来我们看脚本怎么做 <a class="header-anchor" href="#接下来我们看脚本怎么做" aria-label="Permalink to &quot;接下来我们看脚本怎么做&quot;">​</a></h2><p>现在你已经知道镜像内部长什么样了。下一章我们回到 <code>build_imx6ull_image.sh</code>，看看它是怎么一步一步把这个布局做出来的。</p><p><strong>下一步：</strong> 阅读 <a href="./06_build_imx6ull_image_script">06_build_imx6ull_image_script.md</a>，拆解脚本的设计思路。</p>`,75)])])}const u=a(t,[["render",p]]);export{b as __pageData,u as default};
